// Statistical anomaly detection using Z-score method
const rows = $input.all().map(i => i.json);

if (rows.length < 24) {
  return [{ json: { anomalies: [], metrics: rows, insufficient_data: true } }];
}

function stats(arr) {
  const mean = arr.reduce((a, b) => a + b, 0) / arr.length;
  const variance = arr.reduce((sum, x) => sum + Math.pow(x - mean, 2), 0) / arr.length;
  return { mean, std: Math.sqrt(variance) };
}

const revenues = rows.map(r => parseFloat(r.revenue));
const orderCounts = rows.map(r => parseInt(r.order_count));
const failRates = rows.map(r => parseInt(r.failed_orders) / Math.max(parseInt(r.order_count), 1));

const revStats = stats(revenues);
const countStats = stats(orderCounts);
const failStats = stats(failRates);

const anomalies = [];
const Z_THRESHOLD = 2.5; // Flag if > 2.5 standard deviations from mean

for (const row of rows.slice(0, 6)) { // Check last 6 hours
  const revZ = Math.abs((parseFloat(row.revenue) - revStats.mean) / (revStats.std || 1));
  const countZ = Math.abs((parseInt(row.order_count) - countStats.mean) / (countStats.std || 1));
  const failRate = parseInt(row.failed_orders) / Math.max(parseInt(row.order_count), 1);
  const failZ = Math.abs((failRate - failStats.mean) / (failStats.std || 1));

  if (revZ > Z_THRESHOLD) {
    anomalies.push({
      type: 'revenue_anomaly',
      hour: row.hour,
      value: row.revenue,
      expected: revStats.mean.toFixed(2),
      z_score: revZ.toFixed(2),
      severity: revZ > 4 ? 'critical' : 'warning',
      direction: parseFloat(row.revenue) > revStats.mean ? 'spike' : 'drop'
    });
  }

  if (failRate > 0.1 || failZ > Z_THRESHOLD) {
    anomalies.push({
      type: 'high_failure_rate',
      hour: row.hour,
      failed: row.failed_orders,
      total: row.order_count,
      rate: (failRate * 100).toFixed(1) + '%',
      severity: failRate > 0.2 ? 'critical' : 'warning'
    });
  }
}

const summary = {
  period: '7 days',
  total_revenue: revenues.reduce((a, b) => a + b, 0).toFixed(2),
  avg_hourly_revenue: revStats.mean.toFixed(2),
  avg_hourly_orders: countStats.mean.toFixed(1),
  anomaly_count: anomalies.length,
  anomalies
};

return [{ json: summary }];

